{"file_path": "/home/nahom/Desktop/Others/EaglePointAI/vibe-coding-projects/campus-learn-operations-suite-sys/repo/backend/src/auth/jwt.rs", "content": "use chrono::{Duration, Utc};
use jsonwebtoken::{decode, encode, DecodingKey, EncodingKey, Header, Validation};
use serde::{Deserialize, Serialize};

use crate::config::AppConfig;

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct Claims {
    pub sub: String, // user uuid
    pub username: String,
    pub role: String,
    pub exp: i64,
    pub iat: i64,
}

pub fn generate_token(
    config: &AppConfig,
    user_uuid: &str,
    username: &str,
    role: &str,
) -> Result<(String, i64), jsonwebtoken::errors::Error> {
    let now = Utc::now();
    let expires_in = config.jwt_expiration_hours * 3600;
    let exp = (now + Duration::hours(config.jwt_expiration_hours)).timestamp();

