{"file_path": "/home/nahom/Desktop/Others/EaglePointAI/vibe-coding-projects/campus-learn-operations-suite-sys/repo/backend/src/middleware/auth_guard.rs", "content": "use rocket::http::Status;
use rocket::request::{FromRequest, Outcome, Request};
use rocket::serde::json::Json;

use crate::auth::jwt::{validate_token, Claims};
use crate::config::AppConfig;
use crate::utils::errors::ApiError;

pub struct AuthenticatedUser {
    pub claims: Claims,
}

#[rocket::async_trait]
impl<'r> FromRequest<'r> for AuthenticatedUser {
    type Error = Json<ApiError>;

    async fn from_request(req: &'r Request<'_>) -> Outcome<Self, Self::Error> {
        let config = req
            .rocket()
            .state::<AppConfig>()
            .expect("AppConfig not configured");

        let token = req
            .headers()
            .get_one("Authorization")
            .and_then(|header| header.strip_prefix("Bearer "));

        match token {
            Some(token) => match validate_token(config, token) {
                Ok(claims) => Outcome::Success(AuthenticatedUser { claims }),
                Err(_) => Outcome::Error((
                    Status::Unauthorized,
                    Json(ApiError::unauthorized("Invalid or expired token")),
                )),
            },
            None => Outcome::Error((
                Status::Unauthorized,
                Json(ApiError::unauthorized("Missing authorization header")),
            )),
        }
    }
}

pub struct RoleGuard<const ROLE: &'static str> {
    pub user: AuthenticatedUser,
}

macro_rules! impl_role_guard {
    ($name:ident, $role:expr) => {
        pub struct $name {
            pub claims: Claims,
        }

        #[rocket::async_trait]
        impl<'r> FromRequest<'r> for $name {
            type Error = Json<ApiError>;

            async fn from_request(req: &'r Request<'_>) -> Outcome<Self, Self::Error> {
                let user = match AuthenticatedUser::from_request(req).await {
                    Outcome::Success(u) => u,
                    Outcome::Error(e) => return Outcome::Error(e),
                    Outcome::Forward(f) => return Outcome::Forward(f),
                };

                if user.claims.role == $role || user.claims.role == "admin" {
                    Outcome::Success(Self {
                        claims: user.claims,
                    })
                } else {
                    Outcome::Error((
                        Status::Forbidden,
                        Json(ApiError::forbidden("Insufficient permissions")),
                    ))
                }
            }
        }
    };
}

impl_role_guard!(AdminGuard, "admin");
impl_role_guard!(StaffGuard, "staff");
impl_role_guard!(InstructorGuard, "instructor");
impl_role_guard!(ReviewerGuard, "reviewer");
"}

