use crate::auth::AUTH;

#[component]
pub fn MainLayout() -> Element {
    let auth = AUTH.read();

    rsx! {
        div { class: "app-container",
            if auth.is_authenticated {
                nav { class: "sidebar",
                    div { class: "sidebar-header",
                        h2 { class: "sidebar-title", "CampusLearn" }
                    }
                    div { class: "sidebar-nav",
                        Link { to: crate::Route::Dashboard {}, class: "nav-item", "Dashboard" }
                        if auth.is_admin() {
                            Link { to: crate::Route::Dashboard {}, class: "nav-item", "Users" }
                        }
                        if auth.is_staff_or_above() {
                            Link { to: crate::Route::Dashboard {}, class: "nav-item", "Courses" }
                            Link { to: crate::Route::Dashboard {}, class: "nav-item", "Bookings" }
                            Link { to: crate::Route::Dashboard {}, class: "nav-item", "Approvals" }
                        }
                        if auth.is_admin() {
                            Link { to: crate::Route::Dashboard {}, class: "nav-item", "Compliance" }
                            Link { to: crate::Route::Dashboard {}, class: "nav-item", "Audit Log" }
                        }
                    }
                    div { class: "sidebar-footer",
                        if let Some(user) = &auth.user {
                            div { class: "user-info",
                                span { class: "user-name", "{user.full_name}" }
                                span { class: "user-role", "{user.role}" }
                            }
                        }
                        button {
                            class: "btn btn-outline btn-sm",
                            onclick: move |_| crate::auth::logout(),
                            "Logout"
                        }
                    }
                }
            }
            main { class: if auth.is_authenticated { "main-content with-sidebar" } else { "main-content" },
                Outlet::<crate::Route> {}
            }
        }
    }
}
"}

