use crate::api;
use crate::auth::{AuthState, AUTH};
use crate::types::{ApiResponse, LoginResponse};

#[derive(serde::Serialize)]
struct LoginPayload {
    username: String,
    password: String,
}

#[component]
pub fn Login() -> Element {
    let mut username = use_signal(String::new);
    let mut password = use_signal(String::new);
    let mut error = use_signal(|| None::<String>);
    let mut loading = use_signal(|| false);
    let mut api_status = use_signal(|| "Checking...".to_string());
    let nav = navigator();

    use_effect(move || {
        spawn(async move {
            match api::check_health().await {
                Ok(h) => api_status.set(format!("Connected ({})", h.status)),
                Err(e) => api_status.set(format!("Offline: {}", e)),
            }
        });
    });

    let handle_login = move |evt: Event<FormData>| {
        evt.prevent_default();
        spawn(async move {
            loading.set(true);
            error.set(None);

            let payload = LoginPayload {
                username: username.read().clone(),
                password: password.read().clone(),
            };

            match api::post::<ApiResponse<LoginResponse>>("/api/v1/auth/login", &payload).await {
                Ok(resp) => {
                    api::set_token(&resp.data.token);
                    *AUTH.write() = AuthState::logged_in(resp.data.user);
                    nav.push(crate::Route::Dashboard {});
                }
                Err(e) => {
                    error.set(Some(format!("Login failed: {}", e)));
                }
            }

            loading.set(false);
        });
    };

    rsx! {
        div { class: "login-page",
            div { class: "login-card",
                div { class: "login-header",
                    h1 { class: "login-title", "CampusLearn" }
                    p { class: "login-subtitle", "Operations Suite" }
                }
                form { class: "login-form", onsubmit: handle_login,
                    div { class: "form-group",
                        label { r#for: "username", "Username" }
                        input {
                            r#type: "text",
                            id: "username",
                            class: "form-input",
                            placeholder: "Enter your username",
                            required: true,
                            value: "{username}",
                            oninput: move |evt| username.set(evt.value()),
                        }
                    }
                    div { class: "form-group",
                        label { r#for: "password", "Password" }
                        input {
                            r#type: "password",
                            id: "password",
                            class: "form-input",
                            placeholder: "Enter your password",
                            required: true,
                            value: "{password}",
                            oninput: move |evt| password.set(evt.value()),
                        }
                    }
                    if let Some(err) = error.read().as_ref() {
                        div { class: "form-error", "{err}" }
                    }
                    button {
                        r#type: "submit",
                        class: "btn btn-primary btn-full",
                        disabled: *loading.read(),
                        if *loading.read() { "Signing in..." } else { "Sign In" }
                    }
                }
                div { class: "login-footer",
                    span { class: "api-status",
                        "API: {api_status}"
                    }
                }
            }
        }
    }
}
"}

