{"file_path": "/home/nahom/Desktop/Others/EaglePointAI/vibe-coding-projects/campus-learn-operations-suite-sys/repo/backend/src/services/seed.rs", "content": "use sqlx::MySqlPool;
use uuid::Uuid;

use crate::auth::password::hash_password;
use crate::repositories::user_repo;

pub async fn seed_default_users(pool: &MySqlPool) -> Result<(), Box<dyn std::error::Error>> {
    // Seed departments
    seed_departments(pool).await?;

    // Seed permissions
    seed_permissions(pool).await?;

    // Seed users
    let count = user_repo::count_users(pool).await?;
    if count > 0 {
        tracing::info!("Users already exist, skipping user seed");
        return Ok(());
    }

    tracing::info!("Seeding default admin and staff accounts");

    let admin_hash = hash_password("Admin@12345678")?;
    user_repo::create_user(
        pool,
        &Uuid::new_v4().to_string(),
        "admin",
        &admin_hash,
        "admin@campuslearn.local",
        "System Administrator",
        "admin",
    )
    .await?;

    let staff_hash = hash_password("Staff@12345678")?;
    user_repo::create_user(
        pool,
        &Uuid::new_v4().to_string(),
        "staff",
        &staff_hash,
        "staff@campuslearn.local",
        "Default Staff",
        "staff",
    )
    .await?;

    tracing::info!("Default users seeded successfully");
    Ok(())
}

async fn seed_departments(pool: &MySqlPool) -> Result<(), sqlx::Error> {
    let count: (i64,) = sqlx::query_as("SELECT COUNT(*) FROM departments")
        .fetch_one(pool)
        .await?;

    if count.0 > 0 {
        return Ok(());
    }

    tracing::info!("Seeding default departments");

    let departments = [
        ("Computer Science", "CS", "Department of Computer Science"),
        ("Mathematics", "MATH", "Department of Mathematics"),
        ("Engineering", "ENG", "Department of Engineering"),
        ("Business", "BUS", "Department of Business Administration"),
    ];

    for (name, code, desc) in departments {
        sqlx::query("INSERT INTO departments (uuid, name, code, description) VALUES (?, ?, ?, ?)")
            .bind(Uuid::new_v4().to_string())
            .bind(name)
            .bind(code)
            .bind(desc)
            .execute(pool)
            .await?;
    }

    Ok(())
}

async fn seed_permissions(pool: &MySqlPool) -> Result<(), sqlx::Error> {
    let count: (i64,) = sqlx::query_as("SELECT COUNT(*) FROM permissions")
        .fetch_one(pool)
        .await?;

    if count.0 > 0 {
        return Ok(());
    }

    tracing::info!("Seeding default permissions");

    let perms = [
        ("admin", "users", "manage"),
        ("admin", "courses", "manage"),
        ("admin", "bookings", "manage"),
        ("admin", "approvals", "manage"),
        ("admin", "compliance", "manage"),
        ("admin", "audit", "read"),
        ("staff", "courses", "create"),
        ("staff", "courses", "read"),
        ("staff", "courses", "update"),
        ("staff", "bookings", "create"),
        ("staff", "bookings", "read"),
        ("staff", "bookings", "update"),
        ("staff", "approvals", "read"),
        ("instructor", "courses", "create"),
        ("instructor", "courses", "read"),
        ("instructor", "courses", "update"),
        ("instructor", "bookings", "create"),
        ("instructor", "bookings", "read"),
        ("reviewer", "courses", "read"),
        ("reviewer", "approvals", "read"),
        ("reviewer", "approvals", "approve"),
        ("viewer", "courses", "read"),
        ("viewer", "bookings", "read"),
    ];

    for (role, resource, action) in perms {
        sqlx::query("INSERT INTO permissions (role, resource, action) VALUES (?, ?, ?)")
            .bind(role)
            .bind(resource)
            .bind(action)
            .execute(pool)
            .await?;
    }

    Ok(())
}
"}

