import unittest


EXPECTED_ROUTES = {
    "/": "Home (redirects to login)",
    "/login": "Login page",
    "/dashboard": "Dashboard page",
}

ROLE_NAV_ITEMS = {
    "admin": ["Dashboard", "Users", "Courses", "Bookings", "Approvals", "Compliance", "Audit Log"],
    "staff": ["Dashboard", "Courses", "Bookings", "Approvals"],
    "instructor": ["Dashboard", "Courses", "Bookings"],
    "reviewer": ["Dashboard", "Courses", "Approvals"],
    "viewer": ["Dashboard"],
}


class TestRouteDefinitions(unittest.TestCase):
    def test_all_expected_routes_defined(self):
        for route in EXPECTED_ROUTES:
            self.assertIsInstance(route, str)
            self.assertTrue(route.startswith("/"))

    def test_admin_has_all_nav_items(self):
        admin_items = ROLE_NAV_ITEMS["admin"]
        self.assertIn("Dashboard", admin_items)
        self.assertIn("Users", admin_items)
        self.assertIn("Audit Log", admin_items)

    def test_viewer_has_minimal_nav(self):
        viewer_items = ROLE_NAV_ITEMS["viewer"]
        self.assertEqual(len(viewer_items), 1)
        self.assertIn("Dashboard", viewer_items)

    def test_all_roles_have_dashboard(self):
        for role, items in ROLE_NAV_ITEMS.items():
            self.assertIn("Dashboard", items, f"{role} missing Dashboard")

    def test_staff_cannot_see_compliance(self):
        self.assertNotIn("Compliance", ROLE_NAV_ITEMS["staff"])

    def test_reviewer_cannot_manage_users(self):
        self.assertNotIn("Users", ROLE_NAV_ITEMS["reviewer"])


if __name__ == "__main__":
    unittest.main()
"}

