import os
import unittest
import urllib.request
import json

BASE_URL = os.environ.get("API_BASE_URL", "http://localhost:8000")


def api_post(path: str, data: dict, token: str = None) -> tuple[int, dict]:
    """Make a POST request and return (status_code, json_body)."""
    url = f"{BASE_URL}{path}"
    headers = {"Content-Type": "application/json", "Accept": "application/json"}
    if token:
        headers["Authorization"] = f"Bearer {token}"
    try:
        body_bytes = json.dumps(data).encode()
        req = urllib.request.Request(url, data=body_bytes, headers=headers, method="POST")
        with urllib.request.urlopen(req, timeout=10) as resp:
            body = json.loads(resp.read().decode())
            return resp.status, body
    except urllib.error.HTTPError as e:
        body = json.loads(e.read().decode()) if e.fp else {}
        return e.code, body
    except Exception as e:
        raise ConnectionError(f"Cannot reach {url}: {e}")


def api_get(path: str, token: str = None) -> tuple[int, dict]:
    """Make a GET request and return (status_code, json_body)."""
    url = f"{BASE_URL}{path}"
    headers = {"Accept": "application/json"}
    if token:
        headers["Authorization"] = f"Bearer {token}"
    try:
        req = urllib.request.Request(url, headers=headers)
        with urllib.request.urlopen(req, timeout=10) as resp:
            body = json.loads(resp.read().decode())
            return resp.status, body
    except urllib.error.HTTPError as e:
        body = json.loads(e.read().decode()) if e.fp else {}
        return e.code, body
    except Exception as e:
        raise ConnectionError(f"Cannot reach {url}: {e}")


class TestAuthLogin(unittest.TestCase):
    def test_login_admin_success(self):
        status, body = api_post("/api/v1/auth/login", {
            "username": "admin",
            "password": "Admin@12345678",
        })
        self.assertEqual(status, 200)
        self.assertTrue(body["success"])
        self.assertIn("token", body["data"])
        self.assertEqual(body["data"]["token_type"], "Bearer")
        self.assertEqual(body["data"]["user"]["role"], "admin")

    def test_login_staff_success(self):
        status, body = api_post("/api/v1/auth/login", {
            "username": "staff",
            "password": "Staff@12345678",
        })
        self.assertEqual(status, 200)
        self.assertTrue(body["success"])
        self.assertEqual(body["data"]["user"]["role"], "staff")

    def test_login_invalid_credentials(self):
        status, body = api_post("/api/v1/auth/login", {
            "username": "admin",
            "password": "wrongpassword1",
        })
        self.assertIn(status, [400, 401])

    def test_login_nonexistent_user(self):
        status, body = api_post("/api/v1/auth/login", {
            "username": "nonexistent",
            "password": "SomePassword1!",
        })
        self.assertIn(status, [400, 401])

    def test_login_empty_body(self):
        status, body = api_post("/api/v1/auth/login", {})
        self.assertIn(status, [400, 422])


class TestAuthMe(unittest.TestCase):
    @classmethod
    def setUpClass(cls):
        status, body = api_post("/api/v1/auth/login", {
            "username": "admin",
            "password": "Admin@12345678",
        })
        if status == 200:
            cls.token = body["data"]["token"]
        else:
            cls.token = None

    def test_me_returns_user_info(self):
        if not self.token:
            self.skipTest("Login failed, cannot test /me")
        status, body = api_get("/api/v1/auth/me", self.token)
        self.assertEqual(status, 200)
        self.assertTrue(body["success"])
        self.assertEqual(body["data"]["username"], "admin")
        self.assertEqual(body["data"]["role"], "admin")

    def test_me_without_token_returns_401(self):
        status, body = api_get("/api/v1/auth/me")
        self.assertEqual(status, 401)

    def test_me_with_invalid_token(self):
        status, body = api_get("/api/v1/auth/me", "invalid.token.here")
        self.assertEqual(status, 401)


if __name__ == "__main__":
    unittest.main()
"}

