    def setUpClass(cls):
        status, body = api_post("/api/v1/auth/login", {
            "username": "admin",
            "password": "Admin@12345678",
        })
        if status == 200:
            cls.token = body["data"]["token"]
        else:
            cls.token = None

    def test_me_returns_user_info(self):
        if not self.token:
            self.skipTest("Login failed, cannot test /me")
        status, body = api_get("/api/v1/auth/me", self.token)
        self.assertEqual(status, 200)
        self.assertTrue(body["success"])
        self.assertEqual(body["data"]["username"], "admin")
        self.assertEqual(body["data"]["role"], "admin")

    def test_me_without_token_returns_401(self):
        status, body = api_get("/api/v1/auth/me")
        self.assertEqual(status, 401)

    def test_me_with_invalid_token(self):
        status, body = api_get("/api/v1/auth/me", "invalid.token.here")
        self.assertEqual(status, 401)


if __name__ == "__main__":
    unittest.main()
"}

