    pool: &MySqlPool, id: i64, title: Option<&str>, description: Option<&str>,
    department_id: Option<i64>, term_id: Option<i64>, max_enrollment: Option<i32>,
) -> Result<(), sqlx::Error> {
    let mut query = String::from("UPDATE courses SET updated_at = NOW()");
    // We build a safe parameterized query dynamically
    let mut bindings: Vec<Box<dyn std::any::Any>> = vec![];
    if let Some(t) = title { query.push_str(", title = ?"); }
    if let Some(d) = description { query.push_str(", description = ?"); }
    if department_id.is_some() { query.push_str(", department_id = ?"); }
    if term_id.is_some() { query.push_str(", term_id = ?"); }
    if max_enrollment.is_some() { query.push_str(", max_enrollment = ?"); }
    query.push_str(" WHERE id = ?");

    // Use a simpler approach - just update all fields
    sqlx::query("UPDATE courses SET title = COALESCE(?, title), description = COALESCE(?, description), department_id = COALESCE(?, department_id), term_id = COALESCE(?, term_id), max_enrollment = COALESCE(?, max_enrollment), updated_at = NOW(), updated_on = NOW() WHERE id = ?")
        .bind(title).bind(description).bind(department_id).bind(term_id).bind(max_enrollment).bind(id)
        .execute(pool).await?;
    Ok(())
}

