pub async fn change_password(
    pool: &State<MySqlPool>,
    user: AuthenticatedUser,
    body: Json<ChangePasswordRequest>,
) -> Result<Json<ApiResponse<&str>>, (Status, Json<ApiError>)> {
    if let Err(validation_errors) = body.validate() {
