        self.assertEqual(dt.hour, 14)
        self.assertEqual(dt.minute, 30)

    def test_24_hour_format(self):
        dt = parse_effective_date("12/31/2025 14:00")
        self.assertEqual(dt.hour, 14)

    def test_iso_format(self):
