use gloo_net::http::Request;
use gloo_storage::{LocalStorage, Storage};
use serde::de::DeserializeOwned;

const STORAGE_TOKEN_KEY: &str = "campus_learn_token";

fn api_base() -> String {
    web_sys::window()
        .and_then(|w| w.location().origin().ok())
        .map(|origin| {
            if origin.contains("3000") || origin.contains("8080") {
                "http://localhost:8000".to_string()
            } else {
                origin
            }
        })
        .unwrap_or_else(|| "http://localhost:8000".to_string())
}

pub fn get_token() -> Option<String> {
    LocalStorage::get::<String>(STORAGE_TOKEN_KEY).ok()
}

pub fn set_token(token: &str) {
    let _ = LocalStorage::set(STORAGE_TOKEN_KEY, token.to_string());
}

pub fn clear_token() {
    LocalStorage::delete(STORAGE_TOKEN_KEY);
}

pub fn is_logged_in() -> bool {
    get_token().is_some()
}

async fn request_get<T: DeserializeOwned>(path: &str) -> Result<T, String> {
    let url = format!("{}{}", api_base(), path);
    let mut req = Request::get(&url);
    if let Some(token) = get_token() {
        req = req.header("Authorization", &format!("Bearer {}", token));
    }
    let resp = req.send().await.map_err(|e| e.to_string())?;
    if resp.ok() {
        resp.json::<T>().await.map_err(|e| e.to_string())
    } else {
        let status = resp.status();
        let text = resp.text().await.unwrap_or_default();
        Err(format!("HTTP {}: {}", status, text))
    }
}

async fn request_post<T: DeserializeOwned>(path: &str, body: &impl serde::Serialize) -> Result<T, String> {
    let url = format!("{}{}", api_base(), path);
    let mut req = Request::post(&url).header("Content-Type", "application/json");
    if let Some(token) = get_token() {
        req = req.header("Authorization", &format!("Bearer {}", token));
    }
    let resp = req.json(body).map_err(|e| e.to_string())?.send().await.map_err(|e| e.to_string())?;
    if resp.ok() {
        resp.json::<T>().await.map_err(|e| e.to_string())
    } else {
        let status = resp.status();
        let text = resp.text().await.unwrap_or_default();
        Err(format!("HTTP {}: {}", status, text))
    }
}

