    let mut logs = use_signal(|| Vec::<AuditLogEntry>::new());
    let mut loading = use_signal(|| true);

    use_effect(move || {
        spawn(async move {
            loading.set(true);
            if let Ok(r) = api::list_audit_logs(Some(200)).await { logs.set(r.data); }
