16	    let mut new_lesson_body = use_signal(String::new);
17	    let mut show_add_lesson = use_signal(|| false);
18	    let uuid_clone = uuid.clone();
19	
20	    use_effect(move || {
21	        let u = uuid_clone.clone();
22	        spawn(async move {
23	            loading.set(true);
24	            if let Ok(r) = api::get_course(&u).await {
25	                title.set(r.data.title.clone());
26	                desc.set(r.data.description.clone().unwrap_or_default());
27	                course.set(Some(r.data));
28	            }
29	            if let Ok(r) = api::get_sections(&u).await { sections.set(r.data); }
30	            loading.set(false);
31	        });
32	    });
33	
34	    let save_course = {
35	        let uuid = uuid.clone();
36	        move |_: Event<MouseData>| {
37	            let t = title.read().clone();
38	            let d = desc.read().clone();
39	            let u = uuid.clone();
40	            spawn(async move {
41	                let d_opt = if d.is_empty() { None } else { Some(d.as_str()) };
42	                match api::update_course(&u, Some(&t), d_opt).await {
43	                    Ok(_) => ToastManager::success("Course saved"),
44	                    Err(e) => ToastManager::error(format!("Save failed: {}", e)),
45	                }
46	            });
47	        }
48	    };
49	
50	    let add_section = {
51	        let uuid = uuid.clone();
52	        move |_: Event<MouseData>| {
53	            let st = new_section_title.read().clone();
54	            let u = uuid.clone();
55	            let count = sections.read().len() as i32;
56	            spawn(async move {
57	                if st.is_empty() { ToastManager::error("Section title required"); return; }
58	                match api::create_section(&u, &st, count + 1).await {
59	                    Ok(_) => {
60	                        ToastManager::success("Section added");
61	                        new_section_title.set(String::new());
62	                        if let Ok(r) = api::get_sections(&u).await { sections.set(r.data); }
63	                    }
